367	// ensureCheckpointAvailable makes sure the checkpoint referenced by HEAD is
368	// present locally before the attach writes to it. Without this guard, attach
369	// would create a fresh session 0 under the same ID and overwrite the original
370	// session data on push.
371	//
372	// Only the local branch counts — remote-tracking presence is not enough.
373	// If only the remote-tracking ref exists, a subsequent WriteCommitted creates
374	// a brand-new orphan local branch with an empty tree, which would clobber
375	// the remote on push.
376	//
377	// Fast path: check local refs directly — no network. If missing, trigger the
378	// metadata fetch fallback chain used by `entire resume` (which advances the
379	// local ref on success) and re-check. Returns a possibly-freshly-opened repo
380	// handle so go-git sees any newly fetched packfiles.
381	func ensureCheckpointAvailable(ctx, logCtx context.Context, repo *git.Repository, checkpointID id.CheckpointID, isExistingCheckpoint bool) (*git.Repository, error) {
382		if !isExistingCheckpoint {
383			return repo, nil
384		}
385	
386		v2Only := settings.CheckpointsVersion(logCtx) == 2
387	
388		present, readErr := checkpointPresentLocally(ctx, repo, checkpointID, v2Only)
389		if readErr != nil {
390			return repo, fmt.Errorf("failed to read checkpoint %s: %w", checkpointID, readErr)
391		}
392		if present {
393			return repo, nil
394		}
395	
396		// Missing locally — try to refresh, then re-check. Use the same fetch
397		// chain `entire resume` uses for the active storage version (v2 refs live
398		// under refs/entire/, not refs/heads/, so v1 and v2 need different
399		// refspecs).
400		freshRepo, fetchErr := refreshCheckpointRefs(ctx, v2Only)
401		if fetchErr != nil {
402			logging.Warn(logCtx, "failed to refresh metadata branch before attach; proceeding with local state",
403				slog.String("error", fetchErr.Error()))
404		} else {
405			repo = freshRepo
406			present, readErr = checkpointPresentLocally(ctx, repo, checkpointID, v2Only)
407			if readErr != nil {
408				return repo, fmt.Errorf("failed to read checkpoint %s after refresh: %w", checkpointID, readErr)
409			}
410			if present {
411				return repo, nil
412			}
413		}
414	
415		branchDescription := "entire/checkpoints/v1 branch"
416		if v2Only {
417			branchDescription = "v2 /main ref"
418		}
419		return repo, fmt.Errorf(
420			"checkpoint %s referenced by HEAD is missing from the local %s after a refresh attempt. Creating a fresh checkpoint here would overwrite the original session data on push. Run:\n\n    %s\n\nthen re-run attach. If the colleague who made this commit hasn't pushed their checkpoint metadata yet, ask them to do so first",
421			checkpointID.String(), branchDescription, suggestCheckpointFetchCommand(logCtx, v2Only),
422		)
423	}
