425	// refreshCheckpointRefs runs the resume-equivalent fetch chain for the storage
426	// version we're about to write to. Returns a freshly-opened repo so go-git
427	// sees any newly-fetched packfiles and ref updates.
428	func refreshCheckpointRefs(ctx context.Context, v2Only bool) (*git.Repository, error) {
429		if v2Only {
430			_, repo, err := getV2MetadataTree(ctx)
431			return repo, err
432		}
433		_, repo, err := getMetadataTree(ctx)
434		return repo, err
435	}
