437	// checkpointPresentLocally reports whether the checkpoint already exists on
438	// the local ref we would write to. For v1 / dual-write, that's the local
439	// entire/checkpoints/v1 branch (remote-tracking alone is not enough — see
440	// ensureCheckpointAvailable). For v2-only mode, it's the v2 /main ref, which
441	// has no remote-tracking analog and is therefore already local-only by
442	// construction.
443	func checkpointPresentLocally(ctx context.Context, repo *git.Repository, checkpointID id.CheckpointID, v2Only bool) (bool, error) {
444		if v2Only {
445			v2URL, urlErr := remote.FetchURL(ctx)
446			if urlErr != nil {
447				logging.Debug(ctx, "attach: using origin for v2 store fetch remote",
448					slog.String("error", urlErr.Error()),
449				)
450			}
451			summary, err := cpkg.NewV2GitStore(repo, v2URL).ReadCommitted(ctx, checkpointID)
452			if err != nil {
453				return false, err //nolint:wrapcheck // Caller wraps with checkpoint ID context
454			}
455			return summary != nil, nil
456		}
457	
458		localRef := plumbing.NewBranchReferenceName(paths.MetadataBranchName)
459		if _, err := repo.Reference(localRef, true); err != nil {
460			// Local branch ref doesn't exist — treat as "not present locally".
461			// We deliberately do not fall back to remote-tracking: see
462			// ensureCheckpointAvailable's docstring.
463			return false, nil //nolint:nilerr // Missing ref is the "absent" signal, not an error.
464		}
465		summary, err := cpkg.NewGitStore(repo).ReadCommitted(ctx, checkpointID)
466		if err != nil {
467			return false, err //nolint:wrapcheck // Caller wraps with checkpoint ID context
468		}
469		return summary != nil, nil
470	}
